import { Component, h, State } from '@stencil/core';

const LS_LEVEL_PRICE = 'dofunity-familier-level-price';
const LS_LEVEL1_PRICE = 'dofunity-familier-level1-price';

type LevelRow = {
  level: number;
  savedLevels: number;
  maxPurchasePrice: number;
  maxPremiumVsLevel1: number;
};

@Component({
  tag: 'app-familier-profit-level',
  styleUrl: 'app-familier-profit-level.css',
  shadow: false,
})
export class AppFamilierProfitLevel {
  @State() levelPriceInput = '';
  @State() level1PriceInput = '';

  componentWillLoad() {
    try {
      const savedLevelPrice = localStorage.getItem(LS_LEVEL_PRICE);
      const savedLevel1Price = localStorage.getItem(LS_LEVEL1_PRICE);
      if (savedLevelPrice != null) this.levelPriceInput = savedLevelPrice;
      if (savedLevel1Price != null) this.level1PriceInput = savedLevel1Price;
    } catch {
      /**/
    }
  }

  parseInput(raw: string): number {
    const parsed = parseFloat(raw.replace(/\s/g, '').replace(',', '.'));
    return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
  }

  formatKamas(n: number): string {
    return `${Math.round(n).toLocaleString('fr-FR')} k`;
  }

  saveInputs() {
    try {
      if (this.levelPriceInput.trim() === '') localStorage.removeItem(LS_LEVEL_PRICE);
      else localStorage.setItem(LS_LEVEL_PRICE, this.levelPriceInput.trim());
      if (this.level1PriceInput.trim() === '') localStorage.removeItem(LS_LEVEL1_PRICE);
      else localStorage.setItem(LS_LEVEL1_PRICE, this.level1PriceInput.trim());
    } catch {
      /**/
    }
  }

  getRows(levelPrice: number, level1Price: number): LevelRow[] {
    const rows: LevelRow[] = [];
    for (let level = 1; level <= 100; level++) {
      const savedLevels = level - 1;
      const maxPremiumVsLevel1 = savedLevels * levelPrice;
      const maxPurchasePrice = level1Price + maxPremiumVsLevel1;
      rows.push({
        level,
        savedLevels,
        maxPurchasePrice,
        maxPremiumVsLevel1,
      });
    }
    return rows;
  }

  render() {
    const levelPrice = this.parseInput(this.levelPriceInput);
    const level1Price = this.parseInput(this.level1PriceInput);
    const rows = this.getRows(levelPrice, level1Price);

    return (
      <div class="familier-profit-level">
        <h1>Rentabilité achat familier par niveau (1 à 100)</h1>
        <p class="intro">
          Règle de calcul: <strong>prix max d'achat</strong> = prix d'un familier niveau 1 + (niveaux déjà montés ×
          prix par niveau).
        </p>

        <div class="params">
          <label>
            Prix par niveau (kamas)
            <input
              type="text"
              inputMode="decimal"
              placeholder="ex. 25000"
              value={this.levelPriceInput}
              onInput={(e) => {
                this.levelPriceInput = (e.target as HTMLInputElement).value;
              }}
              onBlur={() => this.saveInputs()}
            />
          </label>
          <label>
            Prix d'un familier niveau 1 (optionnel)
            <input
              type="text"
              inputMode="decimal"
              placeholder="ex. 500000"
              value={this.level1PriceInput}
              onInput={(e) => {
                this.level1PriceInput = (e.target as HTMLInputElement).value;
              }}
              onBlur={() => this.saveInputs()}
            />
          </label>
        </div>

        <table class="table">
          <thead>
            <tr>
              <th>Niveau</th>
              <th>Niveaux déjà montés</th>
              <th>Surprix max vs niveau 1</th>
              <th>Prix max d'achat rentable</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row) => (
              <tr key={row.level}>
                <td>{row.level}</td>
                <td>{row.savedLevels}</td>
                <td>{this.formatKamas(row.maxPremiumVsLevel1)}</td>
                <td class="max-price">{this.formatKamas(row.maxPurchasePrice)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }
}
