import { Component, h, State } from '@stencil/core';
import { Item } from '../../components';
import { RootCategory } from '../../types/Item';


@Component({
  tag: 'app-home',
  styleUrl: 'app-home.css',
  shadow: false,
})

//

export class AppHome {
  API_URL: string = 'http://localhost:2989';
  @State() currentDisplayItem:Item = undefined;
  @State() currentCategoryId: number = 1;
  @State() items: Item[];
  @State() rootCategories: RootCategory[];
  @State() renderLimit: number = 200;
  async componentWillLoad() {
    //this.items = await this.fetchFromApi("/items/items/average-prices");
    // this.sortByPercentageVariation();
    // this.rootCategories = await this.fetchFromApi("/rootCategories");
  }

  setLookUpItem(itemId:number){
    const item = this.items.find((item)=>item.id == itemId);
    if(item){
      this.currentDisplayItem = item;
    }
  }


  async fetchFromApi(route: string) {
    const response = await fetch(this.API_URL + route);
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
    return await response.json();

  }

  sortByPercentageVariation() {
    this.items = [...this.items].sort((a, b) => {
      const variationA = this.calculatePercentageVariation(a);
      const variationB = this.calculatePercentageVariation(b);
      return variationB - variationA; // Tri décroissant
    });
  }

  calculatePercentageVariation(item: Item): number {
    if (item.averagePrices.length < 2) return 0;
    const prices = item.averagePrices.map((price) => price.averagePrice);
    const latestPrice = prices[prices.length - 1];
    const previousPrice = prices[prices.length - 2];
    if (previousPrice === 0) return 0; // Évite la division par zéro
    return ((latestPrice - previousPrice) / previousPrice) * 100;
  }

  render() {
    return (
      <div class="app-home">
        {/* <div>

          <input type="number" value={this.renderLimit} onChange={(e) => this.renderLimit = (e.target as any).value}></input>
          <select onChange={(e) => this.currentCategoryId = (e.target as any).value}>
            {this.rootCategories.map((rootcat) => {
              return <option value={rootcat.id}>{rootcat.name}</option>
            })}
          </select>
          <div>
            <datalist id="suggestions">
              {this.items.map((item)=>{
                return <option value={item.id}>{item.name}</option>
              })}
            </datalist>
            <input onChange={(e)=>{this.setLookUpItem((e.target as any).value )}} autoComplete="on" list="suggestions" />
          </div>
        </div>
        {this.currentDisplayItem ? <div><div class="row"><item-lookup-component item={this.currentDisplayItem}></item-lookup-component></div></div> : 
          this.items.filter((item) => item.averagePrices != null && item.averagePrices.length != 0).filter((item) => item.category.rootCategory.id == this.currentCategoryId).slice(0, this.renderLimit).map((item) => {
            return <div class="row"><item-lookup-component item={item}></item-lookup-component></div>
          })
        } */}
        <item-recipe-component></item-recipe-component>
      </div>
    );
  }
}
