import { Component, State, h } from '@stencil/core';
import { Category, Item, RecipeIngredient, RootCategory, Rune, runeDetails } from '../../types/Item';

type CraftProfessionFilter = 'all' | 'forgeron' | 'sculpteur';

/** Retire les accents pour matcher sur les noms de types d'objets (API DofusDB, français). */
function stripAccents(s: string): string {
  return s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

/**
 * Heuristique métier d'artisanat : basée sur le nom du type d'objet (catégorie).
 * Sculpteur : bois / arcs / bâtons / baguettes. Forgeron : métal (armes de mêlée, outils, anneaux, etc.).
 */
function inferCraftFromCategoryName(name: string | undefined): 'forgeron' | 'sculpteur' | null {
  if (!name || !name.trim()) {
    return null;
  }
  const n = stripAccents(name).toLowerCase();

  if (/\b(arc|baguette|baton)\b/.test(n)) {
    return 'sculpteur';
  }

  if (
    /\b(anneau|bouclier|ceinture|dague|epee|hache|marteau|pelle|pioche)\b/.test(n)
  ) {
    return 'forgeron';
  }

  return null;
}

type BreakAttempt = {
  itemBroken: boolean;
  attemptedAt: string;
  observedCoeff?: number;
};

@Component({
  tag: 'item-recipe-component',
  styleUrl: 'item-recipe-component.css',
  shadow: false,
})
export class ItemRecipeComponent {
  API_URL: string = '/api';
  @State() runes: Item[] = [];
  @State() items: Item[] = [];
  @State() focusFilterRuneId:number = 0;
  @State() producedRuneFilterId: number = 0;
  @State() focusMustBeDifferentFromProducedRune: boolean = false;
  @State() isLoading: boolean = true;
  @State() errorMessage: string = '';
  @State() rootCategories:RootCategory[] = [];
  @State() orderDirection:string = "DESC";

  @State() propToSortOn:string = 'breakableRate';

  @State() breakAttempts: Record<number, BreakAttempt> = {};
  @State() levelMinInput = '';
  @State() levelMaxInput = '';
  @State() craftProfession: CraftProfessionFilter = 'all';
  @State() allCategories: Category[] = [];
  @State() selectedCategoryIds: number[] = [];
  @State() categorySearchInput = '';
  @State() isRefreshingItems = false;

  private static readonly DEFAULT_ROOT_CATEGORY_ID = 7;

  async componentWillLoad() {
    this.isLoading = true;
    try {
      const [runesData, roots, categoriesRaw] = await Promise.all([
        this.fetchFromApi('/items/runes'),
        this.fetchFromApi('/rootCategories'),
        this.fetchFromApi('/categories?includeRoot=1'),
      ]);
      this.runes = runesData;
      this.rootCategories = roots;
      const categoriesTyped = categoriesRaw as Category[];
      this.allCategories = [...categoriesTyped].sort((a, b) =>
        stripAccents(a.name).localeCompare(stripAccents(b.name), 'fr'),
      );

      const underDefaultRoot = this.allCategories
        .filter((c) => c.rootCategoryId === ItemRecipeComponent.DEFAULT_ROOT_CATEGORY_ID)
        .map((c) => c.id);
      this.selectedCategoryIds =
        underDefaultRoot.length > 0
          ? [...underDefaultRoot].sort((a, b) => a - b)
          : [...this.allCategories.map((c) => c.id)].sort((a, b) => a - b);

      await this.reloadItemsFromCategories();
    } catch (error) {
      console.error('Error fetching items:', error);
      this.errorMessage = 'Impossible de charger les items. Vérifie que l’API backend tourne.';
    } finally {
      this.isLoading = false;
    }
  }

  matchesCategorySearch(c: Category): boolean {
    const q = stripAccents(this.categorySearchInput.trim()).toLowerCase();
    if (!q) {
      return true;
    }
    return stripAccents(c.name).toLowerCase().includes(q);
  }

  getCategoryGroups(): {
    rootId: number;
    rootName: string;
    categories: Category[];
  }[] {
    const map = new Map<number, { rootId: number; rootName: string; categories: Category[] }>();

    this.allCategories.forEach((c) => {
      if (!this.matchesCategorySearch(c)) {
        return;
      }
      const rootId = c.rootCategoryId ?? 0;
      const rootName = c.rootCategory?.name ?? 'Autre / non classé';
      let entry = map.get(rootId);
      if (!entry) {
        entry = { rootId, rootName, categories: [] };
        map.set(rootId, entry);
      }
      entry.categories.push(c);
    });

    const groups = Array.from(map.values());
    groups.forEach((g) => {
      g.categories.sort((a, b) => stripAccents(a.name).localeCompare(stripAccents(b.name), 'fr'));
    });
    groups.sort((a, b) => stripAccents(a.rootName).localeCompare(stripAccents(b.rootName), 'fr'));
    return groups;
  }

  toggleCategorySelection(categoryId: number, checked: boolean) {
    const next = new Set(this.selectedCategoryIds);
    if (checked) {
      next.add(categoryId);
    } else {
      next.delete(categoryId);
    }
    this.selectedCategoryIds = Array.from(next).sort((a, b) => a - b);
  }

  applyQuickFamily(rootId: number) {
    const ids = this.allCategories.filter((c) => c.rootCategoryId === rootId).map((c) => c.id);
    if (ids.length === 0) {
      return;
    }
    this.selectedCategoryIds = [...ids].sort((a, b) => a - b);
    void this.reloadItemsFromCategories();
  }

  selectAllVisibleCategories() {
    const next = new Set(this.selectedCategoryIds);
    this.allCategories.forEach((c) => {
      if (this.matchesCategorySearch(c)) {
        next.add(c.id);
      }
    });
    this.selectedCategoryIds = Array.from(next).sort((a, b) => a - b);
  }

  clearVisibleCategories() {
    const next = new Set(this.selectedCategoryIds);
    this.allCategories.forEach((c) => {
      if (this.matchesCategorySearch(c)) {
        next.delete(c.id);
      }
    });
    this.selectedCategoryIds = Array.from(next).sort((a, b) => a - b);
  }

  toggleGroupSelection(rootId: number, checked: boolean) {
    const next = new Set(this.selectedCategoryIds);
    this.allCategories.forEach((c) => {
      if ((c.rootCategoryId ?? 0) !== rootId) {
        return;
      }
      if (!this.matchesCategorySearch(c)) {
        return;
      }
      if (checked) {
        next.add(c.id);
      } else {
        next.delete(c.id);
      }
    });
    this.selectedCategoryIds = Array.from(next).sort((a, b) => a - b);
  }

  async fetchAllEquipmentPagesForCategories(categoryIds: number[]): Promise<Item[]> {
    if (categoryIds.length === 0) {
      return [];
    }
    const qs = [...new Set(categoryIds)].sort((a, b) => a - b).join(',');
    const all: Item[] = [];
    let offset = 0;
    const limit = 500;
    while (offset < 50000) {
      const chunk: Item[] = await this.fetchFromApi(
        `/items/equipments/by-category-ids?categoryIds=${encodeURIComponent(qs)}&offset=${offset}&limit=${limit}`,
      );
      if (!Array.isArray(chunk) || chunk.length === 0) {
        break;
      }
      all.push(...chunk);
      if (chunk.length < limit) {
        break;
      }
      offset += limit;
    }
    return all;
  }

  async reloadItemsFromCategories() {
    if (this.selectedCategoryIds.length === 0) {
      this.items = [];
      this.breakAttempts = {};
      return;
    }

    this.isRefreshingItems = true;
    this.errorMessage = '';
    try {
      const merged = await this.fetchAllEquipmentPagesForCategories(this.selectedCategoryIds);
      this.items = await this.processItems(merged);
      this.items = this.items.filter((item) => !isNaN(item.breakableRate));
      await this.loadBreakAttemptsForItems(this.items);
    } catch (error) {
      console.error(error);
      this.errorMessage = 'Erreur lors du chargement des items pour ces types.';
    } finally {
      this.isRefreshingItems = false;
    }
  }

  async processItems(itemsData: Item[]): Promise<Item[]> {
    return Promise.all(
      itemsData.map(async (item) => {
        if (!item.ResultRecipes || !item.characteristics) return item;

        item.totalCraftPrice = this.calculateCraftPrice(item);
        item._runeDetails = this.calculateRuneDetails(item);

        this.setLowestBreakableRate(item);
        this.setBenefice(item);

        return item;
      })
    );
  }

  calculateCraftPrice(item: Item): number {
    return item.ResultRecipes.reduce((total, recipe) => {
      return (
        total +
        recipe.Ingredients.reduce((sum, ingredient: RecipeIngredient) => {
          const price = ingredient.Ingredient?.averagePrices?.[0]?.averagePrice || 0;
          return sum + price * ingredient.quantity;
        }, 0)
      );
    }, 0);
  }

  calculateRuneDetails(item: Item): runeDetails[] {
    const runeDetails: runeDetails[] = [];
    let totalRunePrice = 0;
    let totalFocusRunePrice = 0;

    let focusPrice = 0;
    let bestCharToFocus:Rune;
    item.characteristics.forEach((char) => {
      if (char.from < 0 || !char.characteristic?.runes) return;

      char.characteristic.runes.forEach((rune) => {
        const density = rune.density || 1;

        
        const averagePrice = rune.rune?.averagePrices?.[0]?.averagePrice || 0;
        const value = char.to ? (char.from + char.to) / 2 : char.from;

        const pdb = (((3 * value * density * item.lvl) / 200) + 1) / Math.max(density, 1);
        const priceNoFocus = pdb * averagePrice;
        totalRunePrice += priceNoFocus;


        
        const totalPdbFocus = this.calculateFocusPdb(item, char, density);

        const priceFocus = totalPdbFocus * averagePrice;

        if(priceFocus > focusPrice){
          focusPrice = priceFocus;
          bestCharToFocus = rune;
        }

        totalFocusRunePrice = Math.max(totalFocusRunePrice, priceFocus);

        runeDetails.push({
          runeId: rune.rune?.id || 0,
          type: rune.rune?.name || 'Unknown Rune',
          quantityFocus: totalPdbFocus,
          quantityNoFocus: pdb,
          priceFocus,
          priceNoFocus,
          focusedCharacteristic: char.characteristic.name,
        });
      });
    });

    item.totalRunePrice = totalRunePrice;
    item.totalFocusRunePrice = totalFocusRunePrice;
    item.bestCharToFocus = bestCharToFocus;
    return runeDetails;
  }

  calculateFocusPdb(item: Item, char, density: number): number {
    return item.characteristics.reduce((total, focusChar) => {
      if (focusChar.from < 0) return total;

      const focusValue = focusChar.to
        ? (focusChar.from + focusChar.to) / 2
        : focusChar.from;
      const focusPdb = (((3 * focusValue * (focusChar.characteristic.runes[0]?.density || 1) * item.lvl) / 200) + 1);

      return total + (focusChar.characteristic.id === char.characteristic.id ? focusPdb : focusPdb * 0.5);
    }, 0) / Math.max(density, 1);
  }

  setLowestBreakableRate(item: Item) {
    const rateFocus = item.totalCraftPrice / item.totalFocusRunePrice;
    const rateNoFocus = item.totalCraftPrice / item.totalRunePrice;
    const coeff = Math.min(rateFocus, rateNoFocus);

    item.breakableRate = coeff;
    item.minBreakableRateFocus = rateFocus;
    item.minBreakableRateNoFocus = rateNoFocus;

    item._runeDetails.forEach((rune) => {
      rune.quantityFocus *= coeff;
      rune.quantityNoFocus *= coeff;
      rune.priceFocus *= coeff;
      rune.priceNoFocus *= coeff;
    });
  }

  setBenefice(item: Item) {
    const benefitFocus = item.totalFocusRunePrice - item.totalCraftPrice;
    const benefitNoFocus = item.totalRunePrice - item.totalCraftPrice;

    item.benefit = Math.max(benefitFocus, benefitNoFocus);
    item.benefitPercentage = item.totalCraftPrice > 0 ? (item.benefit / item.totalCraftPrice) * 100 : 0;
  }

  async fetchFromApi(route: string) {
    const response = await fetch(this.API_URL + route);
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
    return await response.json();
  }

  async saveBreakAttempt(itemId: number, attempt: BreakAttempt) {
    await fetch(`${this.API_URL}/items/${itemId}/break-attempt`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        itemBroken: attempt.itemBroken,
        attemptedAt: attempt.attemptedAt || null,
        observedCoeff: attempt.observedCoeff ?? null,
      }),
    });
  }

  async loadBreakAttemptsForItems(items: Item[]) {
    const itemIds = items.map((item) => item.id);
    if (itemIds.length === 0) {
      this.breakAttempts = {};
      return;
    }

    const rows = await this.fetchFromApi(`/items/break-attempts?itemIds=${itemIds.join(',')}`);
    const mapped: Record<number, BreakAttempt> = {};

    rows.forEach((row) => {
      mapped[row.itemId] = {
        itemBroken: Boolean(row.itemBroken),
        attemptedAt: row.attemptedAt ? new Date(row.attemptedAt).toISOString().slice(0, 16) : '',
        observedCoeff: row.observedCoeff == null ? undefined : Number(row.observedCoeff),
      };
    });

    this.breakAttempts = mapped;
  }

  sortItems(){
    if(this.orderDirection === "DESC"){
      return this.items.sort((a, b) => b[this.propToSortOn] - a[this.propToSortOn]);
    } else if(this.orderDirection === "ASC"){
      return this.items.sort((a, b) => a[this.propToSortOn] - b[this.propToSortOn]);
    } else return this.items;
  }

  sortByFocusedChar(){
    if(this.focusFilterRuneId === 0) {
      return this.sortItems();
    }
    return this.sortItems().filter((item)=>{
      return item.bestCharToFocus?.rune?.id == this.focusFilterRuneId;
    })
  }

  parseLevelBound(raw: string, fallback: number): number {
    const n = parseInt(String(raw).trim(), 10);
    return Number.isFinite(n) ? n : fallback;
  }

  getLevelFilterBounds(): { active: boolean; min: number; max: number } {
    const minEmpty = this.levelMinInput.trim() === '';
    const maxEmpty = this.levelMaxInput.trim() === '';
    if (minEmpty && maxEmpty) {
      return { active: false, min: 1, max: 200 };
    }
    const parsedMin = minEmpty ? 1 : this.parseLevelBound(this.levelMinInput, 1);
    const parsedMax = maxEmpty ? 200 : this.parseLevelBound(this.levelMaxInput, 200);
    const min = Math.min(parsedMin, parsedMax);
    const max = Math.max(parsedMin, parsedMax);
    return { active: true, min, max };
  }

  matchesLevelFilter(item: Item): boolean {
    const { active, min, max } = this.getLevelFilterBounds();
    if (!active) {
      return true;
    }
    const lvl = item.lvl;
    if (lvl == null || Number.isNaN(Number(lvl))) {
      return false;
    }
    return lvl >= min && lvl <= max;
  }

  matchesCraftFilter(item: Item): boolean {
    if (this.craftProfession === 'all') {
      return true;
    }
    const craft = inferCraftFromCategoryName(item.category?.name);
    return craft === this.craftProfession;
  }

  getFilteredItems() {
    const items = this.sortByFocusedChar().filter((item) => {
      if (this.producedRuneFilterId === 0) {
        return true;
      }

      const producesSelectedRune = item._runeDetails.some((rune) => rune.runeId === this.producedRuneFilterId);
      if (!producesSelectedRune) {
        return false;
      }

      if (!this.focusMustBeDifferentFromProducedRune) {
        return true;
      }

      return item.bestCharToFocus?.rune?.id !== this.producedRuneFilterId;
    });

    return items.filter((item) => this.matchesLevelFilter(item) && this.matchesCraftFilter(item));
  }

  getBreakAttempt(itemId: number): BreakAttempt {
    return this.breakAttempts[itemId] ?? {
      itemBroken: false,
      attemptedAt: '',
      observedCoeff: undefined,
    };
  }

  async updateBreakAttempt(itemId: number, updates: Partial<BreakAttempt>) {
    const current = this.getBreakAttempt(itemId);
    const nextAttempt = {
      ...current,
      ...updates,
    };
    this.breakAttempts = {
      ...this.breakAttempts,
      [itemId]: nextAttempt,
    };
    await this.saveBreakAttempt(itemId, nextAttempt);
  }

  async toggleItemBroken(itemId: number, isBroken: boolean) {
    await this.updateBreakAttempt(itemId, {
      itemBroken: isBroken,
      attemptedAt: isBroken ? new Date().toISOString().slice(0, 16) : '',
      observedCoeff: isBroken ? this.getBreakAttempt(itemId).observedCoeff : undefined,
    });
  }

  getAttemptStatusLabel(itemId: number): string {
    const attempt = this.getBreakAttempt(itemId);
    if (attempt.itemBroken) {
      return 'Brisé';
    }
    return 'En attente';
  }

  getRecommendedFocusLabel(item: Item): string {
    const isNoFocusBetter = item.minBreakableRateFocus > item.minBreakableRateNoFocus;
    if (isNoFocusBetter) {
      return 'No Focus';
    }

    const focusRuneName = item.bestCharToFocus?.rune?.name;
    if (focusRuneName) {
      return `Focus ${focusRuneName}`;
    }

    return 'Focus';
  }

  render() {
    return (
      <div class="items-list">
        <h1>Brisage d'items - suivi des tentatives</h1>

        {!this.errorMessage ? (
          <div class="category-types-panel filters-panel filters-panel--stack">
            <div class="category-types-header">
              <h2 class="category-types-heading">Types d&apos;objets (multi-sélection)</h2>
              <span class="category-types-count">{this.selectedCategoryIds.length} type(s) sélectionné(s)</span>
            </div>
            <p class="category-types-lead">
              Coche plusieurs catégories (ex. Chapeau, Cape, Amulette, Anneau…) puis applique pour recharger la liste.
              Les pages sont agrégées automatiquement côté serveur.
            </p>
            <div class="category-types-toolbar">
              <label class="category-quick-family">
                <span>Raccourci famille</span>
                <select
                  onInput={(e) => {
                    const raw = (e.target as HTMLSelectElement).value;
                    if (!raw) {
                      return;
                    }
                    this.applyQuickFamily(Number(raw));
                    (e.target as HTMLSelectElement).value = '';
                  }}
                >
                  <option value="">Choisir une famille…</option>
                  {this.rootCategories.map((root) => (
                    <option value={root.id}>{root.name}</option>
                  ))}
                </select>
              </label>
              <label class="category-search">
                <span>Filtrer la liste</span>
                <input
                  type="search"
                  placeholder="ex. chapeau, cape, amulette…"
                  value={this.categorySearchInput}
                  onInput={(e) => {
                    this.categorySearchInput = (e.target as HTMLInputElement).value;
                  }}
                />
              </label>
              <div class="category-types-actions">
                <button type="button" class="btn-secondary" onClick={() => this.selectAllVisibleCategories()}>
                  Tout sélectionner (visible)
                </button>
                <button type="button" class="btn-secondary" onClick={() => this.clearVisibleCategories()}>
                  Tout désélectionner (visible)
                </button>
                <button type="button" class="btn-primary" onClick={() => void this.reloadItemsFromCategories()}>
                  Appliquer la sélection
                </button>
              </div>
            </div>

            <div class="category-groups">
              {this.getCategoryGroups().map((group) => {
                const visibleIds = group.categories.map((c) => c.id);
                const selectedInGroup = visibleIds.filter((id) => this.selectedCategoryIds.includes(id));
                const allOn = visibleIds.length > 0 && selectedInGroup.length === visibleIds.length;
                return (
                  <details class="category-group" open>
                    <summary class="category-group-summary">
                      <span class="category-group-title">{group.rootName}</span>
                      <span class="category-group-meta">
                        {selectedInGroup.length}/{visibleIds.length} ·{' '}
                        <button
                          type="button"
                          class="link-button"
                          onClick={(ev) => {
                            ev.preventDefault();
                            ev.stopPropagation();
                            this.toggleGroupSelection(group.rootId, !allOn);
                          }}
                        >
                          {allOn ? 'Tout désélectionner' : 'Tout sélectionner'}
                        </button>
                      </span>
                    </summary>
                    <div class="category-chips">
                      {group.categories.map((c) => (
                        <label class="category-chip">
                          <input
                            type="checkbox"
                            checked={this.selectedCategoryIds.includes(c.id)}
                            onInput={(ev) =>
                              this.toggleCategorySelection(c.id, (ev.target as HTMLInputElement).checked)
                            }
                          />
                          <span>{c.name}</span>
                        </label>
                      ))}
                    </div>
                  </details>
                );
              })}
            </div>

            {this.isRefreshingItems ? (
              <p class="refresh-banner" role="status">
                Mise à jour des items…
              </p>
            ) : null}
          </div>
        ) : null}

        <div class="filters-panel">
          <select onChange={(v)=> this.propToSortOn = ((v.target as any).value)}>
            <option value="breakableRate">Tri par coeff</option>
            <option value="totalCraftPrice">Tri par prix craft</option>
          </select>
          <select onChange={(v)=>{this.orderDirection = (v.target as any).value;} }>
            <option value="DESC">Du + grand au + petit</option>
            <option value="ASC">Du + petit au + grand</option>
          </select>
          <select onChange={(v)=>{ this.focusFilterRuneId = Number((v.target as HTMLSelectElement).value)} }>
            <option value={0}>Filtre focus: aucun</option>
            {this.runes.map((rune)=>{
              return <option value={rune.id}>{rune.name}</option>
            })}
          </select>
          <select onChange={(v)=>{ this.producedRuneFilterId = Number((v.target as HTMLSelectElement).value);} }>
            <option value={0}>Rune produite: toutes</option>
            {this.runes.map((rune)=>{
              return <option value={rune.id}>{rune.name}</option>
            })}
          </select>
          <label class="focus-filter-toggle">
            <input
              type="checkbox"
              checked={this.focusMustBeDifferentFromProducedRune}
              onInput={(event) => {
                this.focusMustBeDifferentFromProducedRune = (event.target as HTMLInputElement).checked;
              }}
            />
            Focus different from selected produced rune
          </label>
        </div>

        <div class="filters-panel filters-panel--sub">
          <span class="filters-panel__title">Niveau</span>
          <label class="filter-inline">
            <span class="filter-inline-label">Min</span>
            <input
              type="number"
              min={1}
              max={200}
              placeholder="1"
              value={this.levelMinInput}
              onInput={(e) => {
                this.levelMinInput = (e.target as HTMLInputElement).value;
              }}
            />
          </label>
          <label class="filter-inline">
            <span class="filter-inline-label">Max</span>
            <input
              type="number"
              min={1}
              max={200}
              placeholder="200"
              value={this.levelMaxInput}
              onInput={(e) => {
                this.levelMaxInput = (e.target as HTMLInputElement).value;
              }}
            />
          </label>
          <select
            class="craft-select"
            onInput={(e) => {
              this.craftProfession = (e.target as HTMLSelectElement).value as CraftProfessionFilter;
            }}
          >
            <option value="all" selected={this.craftProfession === 'all'}>
              Métier : tous
            </option>
            <option value="forgeron" selected={this.craftProfession === 'forgeron'}>
              Métier : forgeron (types métal)
            </option>
            <option value="sculpteur" selected={this.craftProfession === 'sculpteur'}>
              Métier : sculpteur (arc / baguette / bâton)
            </option>
          </select>
          <p class="filters-hint">
            Le métier est déduit du <strong>type d&apos;objet</strong> (nom de catégorie). Les types non reconnus
            disparaissent si tu filtres forgeron ou sculpteur.
          </p>
        </div>

        {this.errorMessage ? (
          <p class="page-error">{this.errorMessage}</p>
        ) : this.isLoading ? (
          <p>Chargement initial…</p>
        ) : (
          <table class="table">
            <thead>
              <tr>
                <th>Item Name</th>
                <th>Craft Cost</th>
                <th>Focus</th>
                <th>Minimum Break Coefficient</th>
                <th>Suivi tentative</th>
                <th>Rune Details</th>
              </tr>
            </thead>
            <tbody>
              {this.getFilteredItems().map((item) => (
                item.totalCraftPrice > 0 && (
                  <tr key={item.id}>
                    <td>{item.name} : {item.category?.name} - lvl {item.lvl}</td>
                    <td>{item.totalCraftPrice.toFixed(0)}</td>
                    <td>{this.getRecommendedFocusLabel(item)}</td>
                    <td>{(Math.min(item.minBreakableRateFocus, item.minBreakableRateNoFocus)*100).toFixed(0)}</td>
                    <td>
                      <div class={`break-attempt ${this.getBreakAttempt(item.id).itemBroken ? 'break-attempt--done' : ''}`}>
                        <span class={`attempt-status ${this.getBreakAttempt(item.id).itemBroken ? 'attempt-status--done' : 'attempt-status--pending'}`}>
                          {this.getAttemptStatusLabel(item.id)}
                        </span>
                        <label class="break-attempt__toggle">
                          <input
                            type="checkbox"
                            checked={this.getBreakAttempt(item.id).itemBroken}
                            onInput={(event) => {
                              void this.toggleItemBroken(item.id, (event.target as HTMLInputElement).checked);
                            }}
                          />
                          Objet cassé
                        </label>
                        <label>
                          Date de tentative
                          <input
                            type="datetime-local"
                            value={this.getBreakAttempt(item.id).attemptedAt}
                            onInput={(event) => {
                              const dateValue = (event.target as HTMLInputElement).value;
                              void this.updateBreakAttempt(item.id, {
                                itemBroken: dateValue ? true : this.getBreakAttempt(item.id).itemBroken,
                                attemptedAt: dateValue,
                              });
                            }}
                          />
                        </label>
                        <label>
                          Coeff observé (optionnel)
                          <input
                            type="number"
                            step="0.01"
                            min="0"
                            placeholder="Ex: 120"
                            value={this.getBreakAttempt(item.id).observedCoeff ?? ''}
                            onInput={(event) => {
                              const value = (event.target as HTMLInputElement).value;
                              const current = this.getBreakAttempt(item.id);
                              const hasCoeff = value !== '';
                              void this.updateBreakAttempt(item.id, {
                                itemBroken: hasCoeff ? true : current.itemBroken,
                                attemptedAt: hasCoeff ? (current.attemptedAt || new Date().toISOString().slice(0, 16)) : current.attemptedAt,
                                observedCoeff: value === '' ? undefined : Number(value),
                              });
                            }}
                          />
                        </label>
                      </div>
                    </td>
                    <td>
                      {item._runeDetails.length > 0 ? (
                        <ul>
                          {item._runeDetails.map((rune) => (
                            <li key={rune.type}>
                              {rune.type}:
                              <ul>
                                <li>Quantity Focus: {rune.quantityFocus.toFixed(1)} (Total: {rune.priceFocus.toFixed(2)})</li>
                                <li>Quantity No Focus: {rune.quantityNoFocus.toFixed(1)} (Total: {rune.priceNoFocus.toFixed(2)})</li>
                              </ul>
                            </li>
                          ))}
                        </ul>
                      ) : 'N/A'}
                    </td>
                  </tr>
                )
              ))}
            </tbody>
          </table>
        )}
      </div>
    );
  }
}
